form:Form.form:Scripts:
		function Filtrar()
{   
	if (arrFILTER.length==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

	FillArray(100);

	Ctrl("main").DoEvent("FILTER");
}

function enable_custom_buttons()
{
	CtrlEnabled("btnFILTER", arrFILTER.length>0?true:false);
}
